// Buffer A — feedback trail (original, MIT).
void mainImage(out vec4 fragColor, in vec2 fragCoord) {
    vec2 uv = fragCoord / iResolution.xy;
    vec3 prev = texture(iChannel0, uv).rgb;
    vec2 p = (2.0 * fragCoord - iResolution.xy) / iResolution.y;
    vec2 m = 0.6 * vec2(cos(iTime * 1.3), sin(iTime * 1.7));
    float d = length(p - m);
    float dot = smoothstep(0.06, 0.0, d);
    vec3 add = dot * (0.5 + 0.5 * cos(vec3(0.0, 2.0, 4.0) + iTime));
    fragColor = vec4(prev * 0.96 + add, 1.0);
}

// Image — tone-map the trail (original, MIT).
void mainImage(out vec4 fragColor, in vec2 fragCoord) {
    vec2 uv = fragCoord / iResolution.xy;
    vec3 col = texture(iChannel0, uv).rgb;
    col = pow(col, vec3(0.7));
    fragColor = vec4(col, 1.0);
}
